// src/lib/rbac.ts
var roleGuard = (roles) => {
  return async (c5, next) => {
    const session = await auth.api.getSession({
      headers: c5.req.raw.headers
    });
    if (!session) {
      return c5.json({ error: { code: "UNAUTHORIZED", message: "You must be logged in" } }, 401);
    }
    const userRole = session.user.role;
    if (!roles.includes(userRole)) {
      return c5.json({ error: { code: "FORBIDDEN", message: "You do not have permission to access this resource" } }, 403);
    }
    c5.set("user", session.user);
    c5.set("session", session.session);
    await next();
  };
};

